/// <summary>
/// Extension of the <c>initializeSalesOrderConfirmationHeader</c> method.
/// </summary>
/// <returns>
/// Initialized record.
/// </returns>
protected SalesConfirmHeaderTmp initializeSalesOrderConfirmationHeader()
{
    SalesConfirmHeaderTmp salesConfirmHeaderTmp = next initializeSalesOrderConfirmationHeader();

    salesConfirmHeaderTmp.ETGSPAINContactName            = this.parmCustConfirmJour().ETGSPAINContactName;        
    salesConfirmHeaderTmp.ETGSPAINAgreementId            = this.parmCustConfirmJour().ETGSPAINAgreementId;
    salesConfirmHeaderTmp.ETGSPAINMonthQuota             = this.parmCustConfirmJour().ETGSPAINMonthQuota;
    salesConfirmHeaderTmp.ETGSPAINPurchPlateDaysNumber   = this.parmCustConfirmJour().ETGSPAINPurchPlateDaysNumber;
    salesConfirmHeaderTmp.ETGSPAINPlateDueDate           = this.parmCustConfirmJour().ETGSPAINPlateDueDate;
    salesConfirmHeaderTmp.ETGSPAINDlvTerm                = this.parmCustConfirmJour().ETGSPAINDlvTerm;
    salesConfirmHeaderTmp.ETGSPAINCustName               = this.parmCustConfirmJour().ETGSPAINCustName;

    return salesConfirmHeaderTmp;
}

/// <summary>
/// Extension of the <c>initializeSalesOrderConfirmationLine</c> method.
/// </summary>
/// <param name="_salesConfirmHeaderTmp">
/// <c>SalesConfirmHeaderTmp</c>.
/// </param>
/// <param name="_confirmationLineSelection">
/// <c>SalesConfirmDPConfirmationLineQuerySelection</c>.
/// </param>
/// <returns>
/// Initialized record.
/// </returns>
protected SalesConfirmDetailsTmp initializeSalesOrderConfirmationLine(SalesConfirmHeaderTmp _salesConfirmHeaderTmp, SalesConfirmDPConfirmationLineQuerySelection _confirmationLineSelection)
{
    SalesConfirmDetailsTmp  salesConfirmDetailsTmp = next initializeSalesOrderConfirmationLine( _salesConfirmHeaderTmp, _confirmationLineSelection);

    salesConfirmDetailsTmp.ETGSPAINPurchUnloadPortId             = _confirmationLineSelection.parmCustConfirmTrans().ETGSPAINPurchUnloadPortId;
    salesConfirmDetailsTmp.ETGSPAINPurchLoadPortId               = _confirmationLineSelection.parmCustConfirmTrans().ETGSPAINPurchLoadPortId;
    salesConfirmDetailsTmp.ETGSPAINAppliedInventLocation         = _confirmationLineSelection.parmCustConfirmTrans().ETGSPAINAppliedInventLocation;
    salesConfirmDetailsTmp.ETGSPAINAppliedInventLocationName     = _confirmationLineSelection.parmCustConfirmTrans().ETGSPAINAppliedInventLocationName;

    return salesConfirmDetailsTmp;
}
